spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 12000;
    var progress = (t % duration) / duration;

    var groundY = H / 2 + 25;
    var origH = 64;
    var newH = 80;

    var origX = W / 2 - 45;
    var newX = W / 2 + 20;
    var barW = 26;

    // Stages
    // 0 - 2s: stage 1 (draw original 80 and new 100 bars)
    // 2s - 4.5s: stage 2 (draw horizontal comparison dotted line, highlight change = 20 in pink)
    // 4.5s - 7.5s: stage 3 (show ratio: Change / Original = 20 / 80)
    // 7.5s - 10s: stage 4 (convert to 25% increase)
    // 10s - 12s: stage 5 (summary)

    var stage = 1;
    if (progress >= 0.16 && progress < 0.38) stage = 2;
    else if (progress >= 0.38 && progress < 0.63) stage = 3;
    else if (progress >= 0.63 && progress < 0.83) stage = 4;
    else if (progress >= 0.83) stage = 5;

    // Ground line
    ctx.beginPath();
    ctx.moveTo(W / 2 - 80, groundY);
    ctx.lineTo(W / 2 + 80, groundY);
    ctx.strokeStyle = '#4B5563';
    ctx.lineWidth = 1.5;
    ctx.stroke();

    // Draw Original bar (80)
    ctx.fillStyle = '#3B82F6'; // Blue
    ctx.fillRect(origX, groundY - origH, barW, origH);
    ctx.strokeStyle = '#2563EB';
    ctx.strokeRect(origX, groundY - origH, barW, origH);

    // Draw New bar (100)
    ctx.fillStyle = '#10B981'; // Green
    ctx.fillRect(newX, groundY - newH, barW, newH);
    ctx.strokeStyle = '#059669';
    ctx.strokeRect(newX, groundY - newH, barW, newH);

    // Labels on bars
    ctx.font = 'bold 10px -apple-system, sans-serif';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';

    ctx.fillStyle = '#FFFFFF';
    ctx.fillText('80', origX + barW / 2, groundY - origH / 2);
    ctx.fillText('100', newX + barW / 2, groundY - newH / 2);

    ctx.fillStyle = '#9CA3AF';
    ctx.font = '9px -apple-system, sans-serif';
    ctx.fillText('Original', origX + barW / 2, groundY + 12);
    ctx.fillText('New', newX + barW / 2, groundY + 12);

    // Dotted line & Highlight change segment
    if (stage >= 2) {
      ctx.beginPath();
      ctx.setLineDash([2, 2]);
      ctx.moveTo(origX + barW, groundY - origH);
      ctx.lineTo(newX, groundY - origH);
      ctx.strokeStyle = '#9CA3AF';
      ctx.lineWidth = 1;
      ctx.stroke();
      ctx.setLineDash([]); // Reset

      // Draw change bracket/indicator on the new bar
      var changeBoxH = newH - origH;
      ctx.fillStyle = 'rgba(236, 72, 153, 0.3)'; // Pink
      ctx.fillRect(newX, groundY - newH, barW, changeBoxH);
      ctx.strokeStyle = '#EC4899';
      ctx.lineWidth = 1.5;
      ctx.strokeRect(newX, groundY - newH, barW, changeBoxH);

      ctx.fillStyle = '#F472B6';
      ctx.font = 'bold 10px -apple-system, sans-serif';
      ctx.fillText('+20', newX + barW / 2, groundY - origH - changeBoxH / 2);
    }

    // Bottom text explanations
    ctx.font = '12px -apple-system, sans-serif';
    ctx.fillStyle = '#9CA3AF';

    if (stage === 1) {
      ctx.fillStyle = '#F3F4F6';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Initial vs Final Values', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('Original value is 80, which grows to a new value of 100.', W / 2, H - 22);
    } else if (stage === 2) {
      ctx.fillStyle = '#F472B6';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Calculate the Change', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('Subtract: 100 - 80 = 20. The value has increased by 20.', W / 2, H - 22);
    } else if (stage === 3) {
      ctx.fillStyle = '#60A5FA';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Divide by Original Value (80)', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('Ratio = Change / Original = 20 / 80 = 1/4 = 0.25', W / 2, H - 22);
    } else if (stage === 4) {
      ctx.fillStyle = '#10B981';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Convert to Percentage', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('Multiply by 100: 0.25 × 100 = 25% Increase.', W / 2, H - 22);
    } else {
      ctx.fillStyle = '#10B981';
      ctx.font = 'bold 18px -apple-system, sans-serif';
      ctx.fillText('Change = +25%', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('The final value is 25% larger than the starting value.', W / 2, H - 22);
    }
  }
};
